original_query:
SELECT DISTINCT "EMP0"."ENAME"
FROM (SELECT "JOB" FROM "EMP" WHERE "ENAME" = 'A') AS "t0"
LEFT JOIN "EMP" AS "EMP0" ON "t0"."JOB" = "EMP0"."JOB";

